"use server";

import { revalidatePath } from "next/cache";
import db, { createDb } from "@/db";
import { todos } from "@/db/schema";

export async function addTodoWithDb(
  database: ReturnType<typeof createDb>,
  title: string
) {
  const trimmed = title.trim();
  if (!trimmed) return;

  database.insert(todos).values({ title: trimmed }).run();
  revalidatePath("/");
}

export async function addTodo(formData: FormData) {
  const title = formData.get("title") as string;
  await addTodoWithDb(db, title ?? "");
}

import { desc } from "drizzle-orm";
import db from "@/db";
import { todos } from "@/db/schema";
import { addTodo } from "@/app/actions";

export default async function Home() {
  const allTodos = db.select().from(todos).orderBy(desc(todos.createdAt)).all();

  return (
    <main className="mx-auto max-w-lg px-4 py-12">
      <h1 className="text-3xl font-bold mb-8">Todos</h1>

      <form action={addTodo} className="flex gap-2 mb-8">
        <input
          type="text"
          name="title"
          placeholder="Add a todo..."
          className="flex-1 rounded-md border border-gray-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
        <button
          type="submit"
          className="rounded-md bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          Add
        </button>
      </form>

      <ul className="space-y-2">
        {allTodos.map((todo) => (
          <li
            key={todo.id}
            className="rounded-md border border-gray-200 bg-white px-4 py-3 text-sm"
          >
            {todo.title}
          </li>
        ))}
      </ul>
    </main>
  );
}

